import{_ as a,o as i,c as e,ae as t}from"./chunks/framework.EHGTsUvI.js";const c=JSON.parse('{"title":"从人工智能到生成式 AI：一条更适合工程师理解的演进路线","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/ai-evolution.md","filePath":"ai-tutorial/ai-evolution.md"}'),r={name:"ai-tutorial/ai-evolution.md"};function o(n,l,u,p,h,s){return i(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="从人工智能到生成式-ai-一条更适合工程师理解的演进路线" tabindex="-1">从人工智能到生成式 AI：一条更适合工程师理解的演进路线 <a class="header-anchor" href="#从人工智能到生成式-ai-一条更适合工程师理解的演进路线" aria-label="Permalink to &quot;从人工智能到生成式 AI：一条更适合工程师理解的演进路线&quot;">​</a></h1><blockquote><p>如果你是这两年才认真看 AI，很容易产生一种错觉：世界像是突然换了版本，昨天还在调模型参数，今天已经在讨论 Agent 和推理模型了。 但把时间线拉长一点就会发现，今天这波生成式 AI 不是凭空冒出来的，它更像前两轮技术积累终于汇到了一起：先是人工设计特征，后来是网络自己学特征，再后来是大规模预训练把很多任务揉进了同一种能力底座里。</p></blockquote><div class="info custom-block"><p class="custom-block-title">这篇文章重点</p><ul><li>为什么“生成式 AI”不是与过去完全割裂的新事物</li><li>特征工程、深度学习和预训练大模型分别解决了什么问题</li><li>为什么规模化训练会带来能力跃迁</li></ul></div><h2 id="_1-特征工程时代-人来告诉模型该看什么" tabindex="-1">1. 特征工程时代：人来告诉模型该看什么 <a class="header-anchor" href="#_1-特征工程时代-人来告诉模型该看什么" aria-label="Permalink to &quot;1. 特征工程时代：人来告诉模型该看什么&quot;">​</a></h2><p>在早期机器学习里，真正决定效果的往往不是模型本身，而是人能否设计出有效特征。</p><p>例如：</p><ul><li>文本分类看词频、n-gram</li><li>推荐系统看点击率、停留时长</li><li>图像任务看边缘、纹理、局部统计</li></ul><p>这种方法的问题在于：</p><ul><li>高度依赖专家经验</li><li>迁移成本高</li><li>面对复杂任务时，手工特征很快碰到上限</li></ul><h2 id="_2-深度学习时代-让模型自己学特征" tabindex="-1">2. 深度学习时代：让模型自己学特征 <a class="header-anchor" href="#_2-深度学习时代-让模型自己学特征" aria-label="Permalink to &quot;2. 深度学习时代：让模型自己学特征&quot;">​</a></h2><p>深度学习的重要变化是：不再要求人显式定义所有特征，而是让多层网络从数据中逐步学习表示。</p><p>这带来了两个直接收益：</p><ul><li>对复杂模式的表达能力更强</li><li>在语音、图像、文本等任务上形成更统一的方法论</li></ul><p>但这一阶段的大多数系统仍然偏“单任务”：</p><ul><li>一个模型做分类</li><li>一个模型做识别</li><li>一个模型做翻译</li></ul><p>系统能力很强，但任务边界依然清晰。</p><h2 id="_3-预训练大模型时代-先学通用表示-再适配具体任务" tabindex="-1">3. 预训练大模型时代：先学通用表示，再适配具体任务 <a class="header-anchor" href="#_3-预训练大模型时代-先学通用表示-再适配具体任务" aria-label="Permalink to &quot;3. 预训练大模型时代：先学通用表示，再适配具体任务&quot;">​</a></h2><p>大模型最关键的转变，是训练方式的变化。</p><p>它不再主要依赖人工标注任务，而是先在海量通用数据上做预训练，学习语言和世界中的统计规律；之后再通过提示词、微调、工具调用、RAG 等方式适应具体任务。</p><p>这意味着同一类模型可以做很多事：</p><ul><li>问答</li><li>摘要</li><li>翻译</li><li>代码生成</li><li>信息抽取</li></ul><p>这不是因为模型“知道所有任务”，而是因为它先学到了一种更通用的表示和生成能力。</p><h2 id="_4-为什么规模化会带来能力跃迁" tabindex="-1">4. 为什么规模化会带来能力跃迁 <a class="header-anchor" href="#_4-为什么规模化会带来能力跃迁" aria-label="Permalink to &quot;4. 为什么规模化会带来能力跃迁&quot;">​</a></h2><p>大模型时代最重要的经验之一，是“规模”本身会改变能力边界：</p><ul><li>更多数据</li><li>更大参数量</li><li>更强训练算力</li></ul><p>当这三者一起增长时，模型会在一些任务上表现出非线性提升。这也是为什么今天的生成式 AI 看起来不像传统 NLP 工具的简单升级，而更像能力级别的跳变。</p><h2 id="_5-这对工程实践有什么影响" tabindex="-1">5. 这对工程实践有什么影响 <a class="header-anchor" href="#_5-这对工程实践有什么影响" aria-label="Permalink to &quot;5. 这对工程实践有什么影响&quot;">​</a></h2><p>理解这条演进路线，会直接影响你对 AI 系统的判断：</p><ul><li>模型不是规则引擎，不能期待绝对确定性</li><li>模型擅长模式泛化，但不擅长天然保存实时事实</li><li>模型本体越来越通用，但系统落地仍然依赖检索、工具和工程边界</li></ul><p>所以今天做 AI 应用，真正重要的往往不是“重新发明一个模型”，而是如何把通用模型能力和外部系统组合起来。</p><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>从人工智能到生成式 AI，并不是从“不会智能”突然跳到“会思考”，而是：</p><ul><li>人工特征逐步让位于自动表示学习</li><li>单任务模型逐步让位于通用预训练模型</li><li>模型能力越来越强，但系统工程的重要性反而更高</li></ul><p>理解这条路线，有助于我们更冷静地看待今天的大模型能力边界。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/1706.03762" target="_blank" rel="noreferrer">Attention Is All You Need</a></li><li><a href="https://arxiv.org/abs/2005.14165" target="_blank" rel="noreferrer">Language Models are Few-Shot Learners</a></li><li>延伸阅读：<a href="./what-is-model.html">解密“模型”与“参数”</a></li></ul>',36)])])}const _=a(r,[["render",o]]);export{c as __pageData,_ as default};
